                }
                Spacer(Modifier.weight(1f))
                IconButton(onClick = onSpeak) { Icon(Icons.Default.VolumeUp, "发音") }
                IconButton(onClick = onFavorite) { Icon(Icons.Default.Favorite, "收藏") }
                IconButton(onClick = onDismiss) { Icon(Icons.Default.Close, "关闭") }
            }
            Text(card.translation, style = MaterialTheme.typography.bodyLarge, color = MaterialTheme.colorScheme.primary)
            if (card.definitions.isNotEmpty()) {
                Spacer(Modifier.height(8.dp))
                Text("📖 释义", style = MaterialTheme.typography.labelMedium)
                card.definitions.forEach { def ->
                    Text("${def.partOfSpeech} ${def.definition}", style = MaterialTheme.typography.bodySmall)
                }
            }
            if (card.examples.isNotEmpty()) {
                Spacer(Modifier.height(8.dp))
                Text("💬 例句", style = MaterialTheme.typography.labelMedium)
                card.examples.forEach { ex ->
                    Text(ex, style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
                }
            }
        }
    }
}

@Composable
fun DictationPanel(
    subtitle: SubtitleCue?,
    onSpeak: (String) -> Unit,
    onNext: () -> Unit,
    onLookup: (String) -> Unit
) {
    if (subtitle == null) {
        Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
            Text("没有字幕可用", color = MaterialTheme.colorScheme.onSurfaceVariant)
        }
        return
    }

    val words = subtitle.text.split(Regex("\\s+")).filter { it.isNotBlank() }
    val answers = remember(subtitle) { words.map { it.replace(Regex("[^\\p{L}\\p{M}'-]"), "") } }
    val inputs = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
    val results = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }

    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
        // Word input boxes
        Card(modifier = Modifier.fillMaxWidth()) {
            Column(modifier = Modifier.padding(16.dp)) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(8.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    words.forEachIndexed { i, word ->
                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
                            OutlinedTextField(
                                value = inputs[i],
                                onValueChange = { inputs[i] = it },
                                modifier = Modifier.width((word.length * 14 + 30).coerceAtLeast(60).dp),
                                singleLine = true,
                                isError = results[i] == "wrong",
                                colors = OutlinedTextFieldDefaults.colors(
                                    focusedBorderColor = if (results[i] == "correct") Color.Green else MaterialTheme.colorScheme.primary
                                )
                            )
                            if (results[i] == "wrong") {
                                Text(answers[i], color = MaterialTheme.colorScheme.error, style = MaterialTheme.typography.labelSmall)
                            }
                            TextButton(onClick = { onLookup(word.replace(Regex("[^\\p{L}\\p{M}'-]"), "")) }) {
                                Text("查词", style = MaterialTheme.typography.labelSmall)
                            }
                        }
                    }
                }
            }
        }

        Spacer(Modifier.height(12.dp))

        // Control buttons
        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
            Button(onClick = { onSpeak(subtitle.text) }) {
                Icon(Icons.Default.VolumeUp, null, Modifier.size(16.dp))
                Spacer(Modifier.width(4.dp))
                Text("朗读")
            }
            Button(onClick = {
                answers.forEachIndexed { i, answer ->
                    results[i] = if (inputs[i].trim().equals(answer, ignoreCase = true)) "correct" else "wrong"
                }
            }) {
                Icon(Icons.Default.Check, null, Modifier.size(16.dp))
                Spacer(Modifier.width(4.dp))
                Text("检查")
            }
            Button(onClick = {
                inputs.indices.forEach { inputs[it] = "" }
                results.indices.forEach { results[it] = "" }
                onNext()
            }) {
                Icon(Icons.Default.ArrowForward, null, Modifier.size(16.dp))
                Spacer(Modifier.width(4.dp))
                Text("下一句")
            }
        }
    }
}

private fun formatTime(ms: Long): String {
    val totalSec = ms / 1000
    val m = totalSec / 60
    val s = totalSec % 60
    return "$m:${s.toString().padStart(2, '0')}"
}
